import React, { useState, useEffect } from 'react';
import { currencyService } from '../../services/currencyService';

const PendingApprovals = () => {
    const [pendingChanges, setPendingChanges] = useState([]);
    const [loading, setLoading] = useState(true);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [rejectReason, setRejectReason] = useState({});

    useEffect(() => {
        loadPendingChanges();
    }, []);

    const loadPendingChanges = async () => {
        try {
            const response = await currencyService.getPendingChanges();
            if (response.success) {
                setPendingChanges(response.data);
            }
        } catch (error) {
            showMessage('error', 'Failed to load pending changes');
        } finally {
            setLoading(false);
        }
    };

    const showMessage = (type, text) => {
        setMessage({ type, text });
        setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    };

    const handleApprove = async (changeId) => {
        try {
            const response = await currencyService.approveChange(changeId);
            if (response.success) {
                showMessage('success', 'Change approved successfully');
                loadPendingChanges();
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to approve');
        }
    };

    const handleReject = async (changeId) => {
        const reason = rejectReason[changeId];
        if (!reason) {
            showMessage('error', 'Please provide a rejection reason');
            return;
        }
        
        try {
            const response = await currencyService.rejectChange(changeId, reason);
            if (response.success) {
                showMessage('success', 'Change rejected');
                loadPendingChanges();
                setRejectReason({});
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to reject');
        }
    };

    const getChangeTypeIcon = (type) => {
        switch(type) {
            case 'add_currency': return 'fa-plus-circle';
            case 'update_rate': return 'fa-edit';
            case 'delete_currency': return 'fa-trash';
            default: return 'fa-clock';
        }
    };

    const getChangeTypeColor = (type) => {
        switch(type) {
            case 'add_currency': return '#28a745';
            case 'update_rate': return '#ffc107';
            case 'delete_currency': return '#dc3545';
            default: return '#6c757d';
        }
    };

    const getChangeTypeText = (type) => {
        switch(type) {
            case 'add_currency': return 'New Currency Request';
            case 'update_rate': return 'Rate Update Request';
            case 'delete_currency': return 'Deletion Request';
            default: return 'Pending Request';
        }
    };

    if (loading) {
        return (
            <div style={{ textAlign: 'center', padding: '2rem' }}>
                <div className="spinner"></div>
                <p>Loading pending approvals...</p>
            </div>
        );
    }

    if (pendingChanges.length === 0) {
        return (
            <div style={{ textAlign: 'center', padding: '3rem' }}>
                <i className="fas fa-check-circle" style={{ fontSize: '3rem', color: '#28a745', marginBottom: '1rem' }}></i>
                <h3>No Pending Approvals</h3>
                <p>All currency change requests have been processed.</p>
            </div>
        );
    }

    return (
        <div className="pending-approvals">
            <div className="section-header">
                <h2><i className="fas fa-clock"></i> Pending Approvals</h2>
                <span style={{ background: '#dc3545', color: 'white', padding: '0.3rem 0.8rem', borderRadius: '20px', fontSize: '0.9rem' }}>
                    {pendingChanges.length} pending
                </span>
            </div>

            {message.text && (
                <div className={`message ${message.type}`} style={{
                    padding: '1rem',
                    marginBottom: '1rem',
                    borderRadius: '8px',
                    backgroundColor: message.type === 'success' ? '#d4edda' : '#f8d7da',
                    color: message.type === 'success' ? '#155724' : '#721c24',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.5rem'
                }}>
                    <i className={`fas fa-${message.type === 'success' ? 'check-circle' : 'exclamation-circle'}`}></i>
                    {message.text}
                </div>
            )}

            <div className="pending-list">
                {pendingChanges.map(change => (
                    <div key={change.id} style={{
                        background: 'white',
                        borderRadius: '12px',
                        padding: '1.5rem',
                        marginBottom: '1rem',
                        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
                        borderLeft: `4px solid ${getChangeTypeColor(change.change_type)}`
                    }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem', flexWrap: 'wrap', gap: '0.5rem' }}>
                            <div style={{
                                display: 'inline-flex',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.3rem 1rem',
                                borderRadius: '20px',
                                backgroundColor: getChangeTypeColor(change.change_type),
                                color: 'white'
                            }}>
                                <i className={`fas ${getChangeTypeIcon(change.change_type)}`}></i>
                                <span>{getChangeTypeText(change.change_type)}</span>
                            </div>
                            <div style={{ color: '#666', fontSize: '0.85rem' }}>
                                <i className="fas fa-calendar"></i> {new Date(change.created_at).toLocaleString()}
                            </div>
                        </div>
                        
                        <div style={{ marginBottom: '1rem' }}>
                            <div style={{ marginBottom: '0.5rem' }}>
                                <strong>Currency:</strong> {change.currency_name} ({change.currency_code})
                            </div>
                            {change.sell_rate && change.buy_rate && (
                                <div style={{ marginBottom: '0.5rem' }}>
                                    <strong>New Rates:</strong>
                                    <span style={{ color: '#dc3545', marginLeft: '0.5rem' }}>Sell: {parseFloat(change.sell_rate).toFixed(4)}</span>
                                    <span style={{ color: '#28a745', marginLeft: '1rem' }}>Buy: {parseFloat(change.buy_rate).toFixed(4)}</span>
                                </div>
                            )}
                            <div style={{ marginBottom: '0.5rem', fontSize: '0.85rem', color: '#666' }}>
                                <strong>Requested by:</strong> {change.requested_by_name}
                            </div>
                        </div>
                        
                        {change.change_type !== 'delete_currency' && (
                            <div style={{
                                background: '#f8f9fa',
                                padding: '1rem',
                                borderRadius: '8px',
                                marginBottom: '1rem'
                            }}>
                                <h4 style={{ marginBottom: '0.5rem', fontSize: '0.9rem' }}>Preview</h4>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <div style={{
                                        width: '50px',
                                        height: '50px',
                                        background: 'rgba(0, 51, 102, 0.1)',
                                        borderRadius: '50%',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center'
                                    }}>
                                        <i className={`fas ${change.currency_icon || 'fa-money-bill-wave'}`} style={{ fontSize: '1.5rem', color: '#003366' }}></i>
                                    </div>
                                    <div>
                                        <div><strong>{change.currency_name}</strong> ({change.currency_code})</div>
                                        <div style={{ fontSize: '0.85rem' }}>
                                            <span style={{ color: '#dc3545' }}>Sell: {parseFloat(change.sell_rate).toFixed(4)}</span>
                                            {' | '}
                                            <span style={{ color: '#28a745' }}>Buy: {parseFloat(change.buy_rate).toFixed(4)}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                        
                        <div style={{ marginBottom: '1rem' }}>
                            <textarea
                                placeholder="Rejection reason (required for rejection)..."
                                value={rejectReason[change.id] || ''}
                                onChange={(e) => setRejectReason({...rejectReason, [change.id]: e.target.value})}
                                rows="2"
                                style={{
                                    width: '100%',
                                    padding: '0.5rem',
                                    border: '1px solid #ddd',
                                    borderRadius: '6px',
                                    fontSize: '0.9rem'
                                }}
                            ></textarea>
                        </div>
                        
                        <div style={{ display: 'flex', gap: '1rem' }}>
                            <button
                                onClick={() => handleApprove(change.id)}
                                style={{
                                    padding: '0.6rem 1.5rem',
                                    background: '#28a745',
                                    color: 'white',
                                    border: 'none',
                                    borderRadius: '6px',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem'
                                }}
                            >
                                <i className="fas fa-check"></i> Approve
                            </button>
                            <button
                                onClick={() => handleReject(change.id)}
                                style={{
                                    padding: '0.6rem 1.5rem',
                                    background: '#dc3545',
                                    color: 'white',
                                    border: 'none',
                                    borderRadius: '6px',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem'
                                }}
                            >
                                <i className="fas fa-times"></i> Reject
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default PendingApprovals;
